// Node.js pseudo-consumer outline for per-tenant Redis stream processing
const redis = require('redis');
const client = redis.createClient({ host: REDIS_HOST, port: REDIS_PORT });

async function processTenantEvents(tenantId) {
  const streamKey = `analytics:tenant:${tenantId}`;
  const groupName = 'analytics-group';

  try {
    // Read pending messages for this tenant
    const pending = await client.xPending(streamKey, groupName);
    if (pending > 0) {
      console.log(`Tenant ${tenantId} has ${pending} pending events`);
    }

    // Process new events
    const messages = await client.xReadGroup(groupName, 'consumer-1', 
      [{ key: streamKey, id: '>' }], { COUNT: 10, BLOCK: 1000 });

    for (const message of messages) {
      await processEvent(message);
      await client.xAck(streamKey, groupName, message.id);
    }
  } catch (error) {
    console.error(`Error processing tenant ${tenantId}:`, error);
  }
}
```

